/* Get random number: "Multiply-With-Carry" generator of G. Marsaglia */
static unsigned int Ran(RanState *state)
{
    state->m_z = 36969 * (state->m_z & 65535) + (state->m_z >> 16);
    state->m_w = 18000 * (state->m_w & 65535) + (state->m_w >> 16);
    return (state->m_z << 16) + state->m_w; /* 32-bit result. */
}

static void RandomizeFreqs(RanState *state, size_t *freqs, int n)
{
    int i;
    for (i = 0; i < n; i++)
    {
        if ((Ran(state) >> 4) % 3 == 0)
            freqs[i] = freqs[Ran(state) % n];
    }
}

static void RandomizeStatFreqs(RanState *state, SymbolStats *stats)
{
    RandomizeFreqs(state, stats->litlens, ZOPFLI_NUM_LL);
    RandomizeFreqs(state, stats->dists, ZOPFLI_NUM_D);
    stats->litlens[256] = 1; /* End symbol. */
}

static void InitRanState(RanState *state)
{
    state->m_w = 1;
    state->m_z = 2;
}

/* Adds the bit lengths. */
/* The three SymbolStats are distinct, fully-allocated objects.  The function
   only writes result's litlens[] and dists[] arrays. */
// clang-format off
static void AddWeighedStatFreqs(const SymbolStats *stats1, double w1,
                                const SymbolStats *stats2, double w2,
                                SymbolStats *result)
__CPROVER_requires(__CPROVER_is_fresh(stats1, sizeof(*stats1)))
__CPROVER_requires(__CPROVER_is_fresh(stats2, sizeof(*stats2)))
__CPROVER_requires(__CPROVER_is_fresh(result, sizeof(*result)))
__CPROVER_assigns(__CPROVER_object_whole(result))
/* Each output entry is the truncated weighted sum of the two inputs.  The
   bounded pipeline reaches only the low loop indices, so sample index 0 of
   each table (any non-quantified element the loop computes works as a witness);
   the loop-bound and +/- mutants all diverge here.  The end symbol is forced
   to 1 after the litlens loop regardless of the weighted value. */
__CPROVER_ensures(result->litlens[0] ==
    (size_t)(stats1->litlens[0] * w1 + stats2->litlens[0] * w2))
__CPROVER_ensures(result->dists[0] ==
    (size_t)(stats1->dists[0] * w1 + stats2->dists[0] * w2))
__CPROVER_ensures(result->litlens[256] == 1)
// clang-format on
{
    size_t i;
    for (i = 0; i < ZOPFLI_NUM_LL; i++)
    {
        result->litlens[i] =
            (size_t)(stats1->litlens[i] * w1 + stats2->litlens[i] * w2);
    }

